module multi_pipe_8bit(
    input clk,
    input rst_n,
    input mul_en_in,
    input [7:0] mul_a,
    input [7:0] mul_b,
    output mul_en_out,
    output [15:0] mul_out
);

    reg mul_en_out_reg;
    reg [7:0] mul_a_reg, mul_b_reg;

    wire [15:0] temp[0:7];

    genvar i;
        for (i = 0; i < 8; i = i + 1) begin : gen_partial_products
            assign temp[i][0] = mul_a_reg[0] & mul_b_reg[i];
            assign temp[i][1] = mul_a_reg[1] & mul_b_reg[i];
            assign temp[i][2] = mul_a_reg[2] & mul_b_reg[i];
            assign temp[i][3] = mul_a_reg[3] & mul_b_reg[i];
            assign temp[i][4] = mul_a_reg[4] & mul_b_reg[i];
            assign temp[i][5] = mul_a_reg[5] & mul_b_reg[i];
            assign temp[i][6] = mul_a_reg[6] & mul_b_reg[i];
            assign temp[i][7] = mul_a_reg[7] & mul_b_reg[i];
        end

    reg [15:0] sum[0:7];
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            for (int i = 0; i < 8; i++) begin
                sum[i] <= 0;
            end
        end else if (mul_en_in) begin
            sum[0] <= temp[0];
            for (int i = 1; i < 8; i++) begin
                sum[i] <= sum[i-1] + temp[i];
            end
        end
    end

    assign mul_en_out = mul_en_out_reg;
    assign mul_out = sum[7];

endmodule
